    57→public class CdsTradeCalculationFunction
    58→    implements CalculationFunction<CdsTrade> {
    59→
    60→  /**
    61→   * The calculations by measure.
    62→   */
    63→  private static final ImmutableMap<Measure, SingleMeasureCalculation> CALCULATORS =
    64→      ImmutableMap.<Measure, SingleMeasureCalculation>builder()
    65→          .put(Measures.PRESENT_VALUE, CdsMeasureCalculations.DEFAULT::presentValue)
    66→          .put(Measures.PV01_CALIBRATED_SUM, CdsMeasureCalculations.DEFAULT::pv01CalibratedSum)
    67→          .put(Measures.PV01_CALIBRATED_BUCKETED, CdsMeasureCalculations.DEFAULT::pv01CalibratedBucketed)
    68→          .put(Measures.PV01_MARKET_QUOTE_SUM, CdsMeasureCalculations.DEFAULT::pv01MarketQuoteSum)
    69→          .put(Measures.PV01_MARKET_QUOTE_BUCKETED, CdsMeasureCalculations.DEFAULT::pv01MarketQuoteBucketed)
    70→          .put(Measures.UNIT_PRICE, CdsMeasureCalculations.DEFAULT::unitPrice)
    71→          .put(CreditMeasures.PRINCIPAL, CdsMeasureCalculations.DEFAULT::principal)
    72→          .put(CreditMeasures.IR01_CALIBRATED_PARALLEL, CdsMeasureCalculations.DEFAULT::ir01CalibratedParallel)
    73→          .put(CreditMeasures.IR01_CALIBRATED_BUCKETED, CdsMeasureCalculations.DEFAULT::ir01CalibratedBucketed)
    74→          .put(CreditMeasures.IR01_MARKET_QUOTE_PARALLEL, CdsMeasureCalculations.DEFAULT::ir01MarketQuoteParallel)
    75→          .put(CreditMeasures.IR01_MARKET_QUOTE_BUCKETED, CdsMeasureCalculations.DEFAULT::ir01MarketQuoteBucketed)
    76→          .put(CreditMeasures.CS01_PARALLEL, CdsMeasureCalculations.DEFAULT::cs01Parallel)
    77→          .put(CreditMeasures.CS01_BUCKETED, CdsMeasureCalculations.DEFAULT::cs01Bucketed)
    78→          .put(CreditMeasures.RECOVERY01, CdsMeasureCalculations.DEFAULT::recovery01)
    79→          .put(CreditMeasures.JUMP_TO_DEFAULT, CdsMeasureCalculations.DEFAULT::jumpToDefault)
    80→          .put(CreditMeasures.EXPECTED_LOSS, CdsMeasureCalculations.DEFAULT::expectedLoss)
    81→          .put(Measures.RESOLVED_TARGET, (rt, smd, rd) -> rt)
    82→          .build();
    83→
    84→  private static final ImmutableSet<Measure> MEASURES = CALCULATORS.keySet();
    85→
    86→  /**
    87→   * Creates an instance.
    88→   */
    89→  public CdsTradeCalculationFunction() {
    90→  }
    91→
    92→  //-------------------------------------------------------------------------
    93→  @Override
    94→  public Class<CdsTrade> targetType() {
    95→    return CdsTrade.class;
    96→  }
    97→
    98→  @Override
    99→  public Set<Measure> supportedMeasures() {
   100→    return MEASURES;
   101→  }
   102→
   103→  @Override
   104→  public Optional<String> identifier(CdsTrade target) {
   105→    return target.getInfo().getId().map(id -> id.toString());
   106→  }
   107→
   108→  @Override
   109→  public Currency naturalCurrency(CdsTrade trade, ReferenceData refData) {
   110→    return trade.getProduct().getCurrency();
   111→  }
   112→
   113→  //-------------------------------------------------------------------------
   114→  @Override
   115→  public FunctionRequirements requirements(
   116→      CdsTrade trade,
   117→      Set<Measure> measures,
   118→      CalculationParameters parameters,
   119→      ReferenceData refData) {
   120→
   121→    // extract data from product
   122→    Cds product = trade.getProduct();
   123→    StandardId legalEntityId = product.getLegalEntityId();
   124→    Currency currency = product.getCurrency();
   125→
   126→    // use lookup to build requirements
   127→    CreditRatesMarketDataLookup lookup = parameters.getParameter(CreditRatesMarketDataLookup.class);
   128→    return lookup.requirements(legalEntityId, currency);
   129→  }
   130→
   131→  //-------------------------------------------------------------------------
   132→  @Override
   133→  public Map<Measure, Result<?>> calculate(
   134→      CdsTrade trade,
   135→      Set<Measure> measures,
   136→      CalculationParameters parameters,
   137→      ScenarioMarketData scenarioMarketData,
   138→      ReferenceData refData) {
   139→
   140→    // resolve the trade once for all measures and all scenarios
   141→    ResolvedCdsTrade resolved = trade.resolve(refData);
   142→
   143→    // use lookup to query market data
   144→    CreditRatesMarketDataLookup ledLookup = parameters.getParameter(CreditRatesMarketDataLookup.class);
   145→    CreditRatesScenarioMarketData marketData = ledLookup.marketDataView(scenarioMarketData);
   146→
   147→    // loop around measures, calculating all scenarios for one measure
   148→    Map<Measure, Result<?>> results = new HashMap<>();
   149→    for (Measure measure : measures) {
   150→      results.put(measure, calculate(measure, resolved, marketData, refData));
   151→    }
   152→    return results;
   153→  }
   154→
   155→  // calculate one measure
   156→  private Result<?> calculate(
   157→      Measure measure,
   158→      ResolvedCdsTrade trade,
   159→      CreditRatesScenarioMarketData marketData,
   160→      ReferenceData refData) {
   161→
   162→    SingleMeasureCalculation calculator = CALCULATORS.get(measure);
   163→    if (calculator == null) {
   164→      return Result.failure(FailureReason.UNSUPPORTED, "Unsupported measure for CdsTrade: {}", measure);
   165→    }
   166→    return Result.of(() -> calculator.calculate(trade, marketData, refData));
   167→  }
