package com.opengamma.strata.pricer.credit;

import java.time.LocalDate;

import com.opengamma.strata.basics.ReferenceData;
import com.opengamma.strata.basics.StandardId;
import com.opengamma.strata.basics.currency.Currency;
import com.opengamma.strata.basics.currency.CurrencyAmount;
import com.opengamma.strata.collect.ArgChecker;
import com.opengamma.strata.market.sensitivity.PointSensitivities;
import com.opengamma.strata.pricer.DiscountingPaymentPricer;
import com.opengamma.strata.pricer.common.PriceType;
import com.opengamma.strata.product.credit.ResolvedCdsTranche;
import com.opengamma.strata.product.credit.ResolvedCdsTrancheTrade;

/**
 * Pricer for CDS tranche products based on ISDA standard model.
 * <p>
 * A CDS tranche is priced using the underlying CDS index curves.
 * The tranche absorbs losses between the attachment and detachment points of the underlying
 * portfolio loss distribution.
 * <p>
 * The present value of the tranche is computed by scaling the underlying index PV by the
 * tranche width (detachmentPoint - attachmentPoint), which represents the expected loss
 * allocation to this specific tranche slice.
 */
public class IsdaCdsTranchePricer {

  /**
   * Default implementation.
   */
  public static final IsdaCdsTranchePricer DEFAULT =
      new IsdaCdsTranchePricer(AccrualOnDefaultFormula.ORIGINAL_ISDA);

  /**
   * The underlying index pricer used to price the base CDS index.
   */
  private final IsdaHomogenousCdsIndexProductPricer indexProductPricer;
  /**
   * The upfront fee pricer.
   */
  private final DiscountingPaymentPricer upfrontPricer;

  /**
   * Constructor specifying the formula to use for the accrued on default calculation.
   *
   * @param formula  the formula
   */
  public IsdaCdsTranchePricer(AccrualOnDefaultFormula formula) {
    this.indexProductPricer = new IsdaHomogenousCdsIndexProductPricer(formula);
    this.upfrontPricer = DiscountingPaymentPricer.DEFAULT;
  }

  //-------------------------------------------------------------------------
  /**
   * Gets the accrual-on-default formula used in this pricer.
   *
   * @return the formula
   */
  public AccrualOnDefaultFormula getAccrualOnDefaultFormula() {
    return indexProductPricer.getAccrualOnDefaultFormula();
  }

  //-------------------------------------------------------------------------
  /**
   * Calculates the present value of the CDS tranche product.
   * <p>
   * The present value is computed by pricing the underlying CDS index as a single-name CDS
   * and scaling it by the tranche width. The tranche width represents the fraction of the
   * portfolio losses that this tranche absorbs (detachmentPoint - attachmentPoint).
   *
   * @param cdsTranche  the tranche product
   * @param ratesProvider  the rates provider
   * @param referenceDate  the reference date
   * @param priceType  the price type (clean or dirty)
   * @param refData  the reference data
   * @return the present value of the tranche
   */
  public CurrencyAmount presentValue(
      ResolvedCdsTranche cdsTranche,
      CreditRatesProvider ratesProvider,
      LocalDate referenceDate,
      PriceType priceType,
      ReferenceData refData) {

    ArgChecker.notNull(cdsTranche, "cdsTranche");
    ArgChecker.notNull(ratesProvider, "ratesProvider");
    ArgChecker.notNull(referenceDate, "referenceDate");
    ArgChecker.notNull(priceType, "priceType");
    ArgChecker.notNull(refData, "refData");

    Currency currency = cdsTranche.getCurrency();
    StandardId indexId = cdsTranche.getCdsIndexId();

    // Price the underlying CDS index as a homogeneous single-name CDS
    CurrencyAmount indexPv = indexProductPricer.presentValue(
        cdsTranche.toResolvedCdsIndex(),
        ratesProvider,
        referenceDate,
        priceType,
        refData);

    // Scale by tranche width to get the tranche-specific present value
    double trancheWidth = cdsTranche.getDetachmentPoint() - cdsTranche.getAttachmentPoint();
    return indexPv.multipliedBy(trancheWidth);
  }

  /**
   * Calculates the present value of the CDS tranche trade.
   * <p>
   * The present value of the trade includes both the product present value and
   * the present value of the upfront fee (if any).
   *
   * @param trade  the tranche trade
   * @param ratesProvider  the rates provider
   * @param referenceDate  the reference date
   * @param priceType  the price type (clean or dirty)
   * @param refData  the reference data
   * @return the present value of the trade
   */
  public CurrencyAmount presentValue(
      ResolvedCdsTrancheTrade trade,
      CreditRatesProvider ratesProvider,
      LocalDate referenceDate,
      PriceType priceType,
      ReferenceData refData) {

    ArgChecker.notNull(trade, "trade");
    ArgChecker.notNull(ratesProvider, "ratesProvider");
    ArgChecker.notNull(referenceDate, "referenceDate");
    ArgChecker.notNull(priceType, "priceType");
    ArgChecker.notNull(refData, "refData");

    CurrencyAmount productPv = presentValue(trade.getProduct(), ratesProvider, referenceDate, priceType, refData);
    if (trade.getUpfrontFee().isPresent()) {
      CurrencyAmount upfrontFeePv =
          upfrontPricer.presentValue(trade.getUpfrontFee().get(), ratesProvider.discountFactors(productPv.getCurrency()));
      return productPv.plus(upfrontFeePv);
    }
    return productPv;
  }

  /**
   * Calculates the price of the CDS tranche, which is the present value per unit notional.
   * <p>
   * The price is computed as the tranche-scaled index price.
   *
   * @param cdsTranche  the tranche product
   * @param ratesProvider  the rates provider
   * @param referenceDate  the reference date
   * @param priceType  the price type (clean or dirty)
   * @param refData  the reference data
   * @return the price
   */
  public double price(
      ResolvedCdsTranche cdsTranche,
      CreditRatesProvider ratesProvider,
      LocalDate referenceDate,
      PriceType priceType,
      ReferenceData refData) {

    ArgChecker.notNull(cdsTranche, "cdsTranche");
    ArgChecker.notNull(ratesProvider, "ratesProvider");
    ArgChecker.notNull(referenceDate, "referenceDate");
    ArgChecker.notNull(priceType, "priceType");
    ArgChecker.notNull(refData, "refData");

    double indexPrice = indexProductPricer.price(
        cdsTranche.toResolvedCdsIndex(),
        ratesProvider,
        referenceDate,
        priceType,
        refData);

    double trancheWidth = cdsTranche.getDetachmentPoint() - cdsTranche.getAttachmentPoint();
    return indexPrice * trancheWidth;
  }

  /**
   * Calculates the point sensitivities of the present value of the CDS tranche.
   * <p>
   * The sensitivities are computed by scaling the underlying index sensitivities
   * by the tranche width.
   *
   * @param cdsTranche  the tranche product
   * @param ratesProvider  the rates provider
   * @param referenceDate  the reference date
   * @param refData  the reference data
   * @return the point sensitivities
   */
  public PointSensitivities presentValueSensitivity(
      ResolvedCdsTranche cdsTranche,
      CreditRatesProvider ratesProvider,
      LocalDate referenceDate,
      ReferenceData refData) {

    ArgChecker.notNull(cdsTranche, "cdsTranche");
    ArgChecker.notNull(ratesProvider, "ratesProvider");
    ArgChecker.notNull(referenceDate, "referenceDate");
    ArgChecker.notNull(refData, "refData");

    PointSensitivities indexSens = indexProductPricer.presentValueSensitivity(
        cdsTranche.toResolvedCdsIndex(),
        ratesProvider,
        referenceDate,
        refData);

    double trancheWidth = cdsTranche.getDetachmentPoint() - cdsTranche.getAttachmentPoint();
    return indexSens.multipliedBy(trancheWidth);
  }

}

