package com.opengamma.strata.measure.credit;

import java.util.HashMap;
import java.util.Map;
import java.util.Optional;
import java.util.Set;

import com.google.common.collect.ImmutableMap;
import com.google.common.collect.ImmutableSet;
import com.opengamma.strata.basics.ReferenceData;
import com.opengamma.strata.basics.StandardId;
import com.opengamma.strata.basics.currency.Currency;
import com.opengamma.strata.basics.currency.CurrencyAmount;
import com.opengamma.strata.calc.Measure;
import com.opengamma.strata.calc.runner.CalculationFunction;
import com.opengamma.strata.calc.runner.CalculationParameters;
import com.opengamma.strata.calc.runner.FunctionRequirements;
import com.opengamma.strata.collect.result.FailureReason;
import com.opengamma.strata.collect.result.Result;
import com.opengamma.strata.data.scenario.CurrencyScenarioArray;
import com.opengamma.strata.data.scenario.DoubleScenarioArray;
import com.opengamma.strata.data.scenario.ScenarioMarketData;
import com.opengamma.strata.measure.Measures;
import com.opengamma.strata.pricer.common.PriceType;
import com.opengamma.strata.pricer.credit.AccrualOnDefaultFormula;
import com.opengamma.strata.pricer.credit.CreditRatesProvider;
import com.opengamma.strata.pricer.credit.IsdaCdsTranchePricer;
import com.opengamma.strata.product.credit.CdsTranche;
import com.opengamma.strata.product.credit.CdsTrancheTrade;
import com.opengamma.strata.product.credit.ResolvedCdsTrancheTrade;

/**
 * Perform calculations on a single {@code CdsTrancheTrade} for each of a set of scenarios.
 * <p>
 * An instance of {@link CreditRatesMarketDataLookup} must be specified.
 * The supported built-in measures are:
 * <ul>
 *   <li>{@linkplain Measures#PRESENT_VALUE Present value}
 *   <li>{@linkplain Measures#UNIT_PRICE Unit price}
 *   <li>{@linkplain Measures#RESOLVED_TARGET Resolved trade}
 * </ul>
 * <p>
 * The "natural" currency is the currency of the CDS tranche, which is limited to be single-currency.
 */
public class CdsTrancheTradeCalculationFunction
    implements CalculationFunction<CdsTrancheTrade> {

  /**
   * The pricer for tranche trades.
   */
  private static final IsdaCdsTranchePricer PRICER =
      new IsdaCdsTranchePricer(AccrualOnDefaultFormula.CORRECT);

  /**
   * The calculations by measure.
   */
  private static final ImmutableMap<Measure, SingleMeasureCalculation> CALCULATORS =
      ImmutableMap.<Measure, SingleMeasureCalculation>builder()
          .put(Measures.PRESENT_VALUE, CdsTrancheTradeCalculationFunction::calculatePresentValue)
          .put(Measures.UNIT_PRICE, CdsTrancheTradeCalculationFunction::calculateUnitPrice)
          .put(Measures.RESOLVED_TARGET, (rt, smd, rd) -> rt)
          .build();

  private static final ImmutableSet<Measure> MEASURES = CALCULATORS.keySet();

  /**
   * Creates an instance.
   */
  public CdsTrancheTradeCalculationFunction() {
  }

  //-------------------------------------------------------------------------
  @Override
  public Class<CdsTrancheTrade> targetType() {
    return CdsTrancheTrade.class;
  }

  @Override
  public Set<Measure> supportedMeasures() {
    return MEASURES;
  }

  @Override
  public Optional<String> identifier(CdsTrancheTrade target) {
    return target.getInfo().getId().map(id -> id.toString());
  }

  @Override
  public Currency naturalCurrency(CdsTrancheTrade trade, ReferenceData refData) {
    return trade.getProduct().getCurrency();
  }

  //-------------------------------------------------------------------------
  @Override
  public FunctionRequirements requirements(
      CdsTrancheTrade trade,
      Set<Measure> measures,
      CalculationParameters parameters,
      ReferenceData refData) {

    // extract data from product
    CdsTranche product = trade.getProduct();
    StandardId legalEntityId = product.getCdsIndexId();
    Currency currency = product.getCurrency();

    // use lookup to build requirements
    CreditRatesMarketDataLookup lookup = parameters.getParameter(CreditRatesMarketDataLookup.class);
    return lookup.requirements(legalEntityId, currency);
  }

  //-------------------------------------------------------------------------
  @Override
  public Map<Measure, Result<?>> calculate(
      CdsTrancheTrade trade,
      Set<Measure> measures,
      CalculationParameters parameters,
      ScenarioMarketData scenarioMarketData,
      ReferenceData refData) {

    // resolve the trade once for all measures and all scenarios
    ResolvedCdsTrancheTrade resolved = trade.resolve(refData);

    // use lookup to query market data
    CreditRatesMarketDataLookup ledLookup = parameters.getParameter(CreditRatesMarketDataLookup.class);
    CreditRatesScenarioMarketData marketData = ledLookup.marketDataView(scenarioMarketData);

    // loop around measures, calculating all scenarios for one measure
    Map<Measure, Result<?>> results = new HashMap<>();
    for (Measure measure : measures) {
      results.put(measure, calculate(measure, resolved, marketData, refData));
    }
    return results;
  }

  // calculate one measure
  private Result<?> calculate(
      Measure measure,
      ResolvedCdsTrancheTrade trade,
      CreditRatesScenarioMarketData marketData,
      ReferenceData refData) {

    SingleMeasureCalculation calculator = CALCULATORS.get(measure);
    if (calculator == null) {
      return Result.failure(FailureReason.UNSUPPORTED, "Unsupported measure for CdsTrancheTrade: {}", measure);
    }
    return Result.of(() -> calculator.calculate(trade, marketData, refData));
  }

  //-------------------------------------------------------------------------
  // present value calculation - loops over scenarios
  private static CurrencyScenarioArray calculatePresentValue(
      ResolvedCdsTrancheTrade trade,
      CreditRatesScenarioMarketData marketData,
      ReferenceData refData) {

    return CurrencyScenarioArray.of(
        marketData.getScenarioCount(),
        i -> {
          CreditRatesProvider ratesProvider = marketData.scenario(i).creditRatesProvider();
          return PRICER.presentValue(trade, ratesProvider, PriceType.DIRTY, refData);
        });
  }

  // unit price calculation - loops over scenarios
  private static DoubleScenarioArray calculateUnitPrice(
      ResolvedCdsTrancheTrade trade,
      CreditRatesScenarioMarketData marketData,
      ReferenceData refData) {

    return DoubleScenarioArray.of(
        marketData.getScenarioCount(),
        i -> {
          CreditRatesProvider ratesProvider = marketData.scenario(i).creditRatesProvider();
          return PRICER.price(trade.getProduct(), ratesProvider, PriceType.DIRTY, refData);
        });
  }

  //-------------------------------------------------------------------------
  @FunctionalInterface
  interface SingleMeasureCalculation {
    public abstract Object calculate(
        ResolvedCdsTrancheTrade trade,
        CreditRatesScenarioMarketData marketData,
        ReferenceData refData);
  }

}

