    buf.append("] / ");
    buf.append(SummarizerUtils.percent(product.getFixedRate()));
    buf.append(" : ");
    buf.append(SummarizerUtils.dateRange(paymentSchedule.getStartDate(), paymentSchedule.getEndDate()));
